1	export type Cell = [number, number];
2	
3	function cellKey(x: number, y: number): string {
4	  return `${x},${y}`;
5	}
6	
7	export function nextGeneration(cells: Cell[]): Cell[] {
8	  const liveCells = new Set<string>();
9	  for (const [x, y] of cells) {
10	    liveCells.add(cellKey(x, y));
11	  }
12	
13	  const neighborCounts = new Map<string, { x: number; y: number; count: number }>();
14	  for (const [x, y] of cells) {
15	    for (let dx = -1; dx <= 1; dx++) {
16	      for (let dy = -1; dy <= 1; dy++) {
17	        if (dx === 0 && dy === 0) continue;
18	        const nx = x + dx;
19	        const ny = y + dy;
20	        const key = cellKey(nx, ny);
21	        const existing = neighborCounts.get(key);
22	        if (existing) {
23	          existing.count += 1;
24	        } else {
25	          neighborCounts.set(key, { x: nx, y: ny, count: 1 });
26	        }
27	      }
28	    }
29	  }
30	
31	  const nextCells: Cell[] = [];
32	  for (const [key, { x, y, count }] of neighborCounts) {
33	    const isAlive = liveCells.has(key);
34	    if (isAlive && (count === 2 || count === 3)) {
35	      nextCells.push([x, y]);
36	    } else if (!isAlive && count === 3) {
37	      nextCells.push([x, y]);
38	    }
39	  }
40	
41	  return nextCells;
42	}
